import{C as t,o as e,c as l,a5 as a,E as h}from"./chunks/framework.CW28V7p_.js";const k=JSON.parse('{"title":"5. Snapshot mirror service","description":"","frontmatter":{},"headers":[],"relativePath":"module-10/5-snapshot-mirror.md","filePath":"module-10/5-snapshot-mirror.md","lastUpdated":1780937944000}'),p={name:"module-10/5-snapshot-mirror.md"},c=Object.assign(p,{setup(r){const i={id:"m10-5-snapshot-mirror",title:"🧠 Mini-check: Snapshot mirror",intro:"2 питання.",questions:[{type:"mcq",q:"Snapshot mirror використовується для:",options:["Public snapshot hosting для community catch-up","Faster catch-up для validators у same region","Backup snapshots до cloud storage","Replace validator's own snapshot creation"],correct:[0,1,2],explanation:"Mirror not replace — validator still creates own. Module 10.5."},{type:"explain",q:"Як setup public snapshot mirror з твого validator?",ideal:`1. Validator вже creates snapshots у \`/home/solana/solana/ledger/snapshot-*\` files (default).

2. Choose HTTP server (nginx, caddy, simple Python http.server). Configure для serve snapshot directory.

3. Configure rsync schedule або symlinks щоб latest snapshots available HTTP-accessible path:
   \`ln -sf /home/solana/solana/ledger/snapshot-*.tar.zst /var/www/snapshots/\`

4. Publish URL у Discord/community:
   \`https://snapshots.lumlabs.io/snapshot-latest.tar.zst\`

5. Others can \`wget\` your snapshots для catch-up:
   \`wget https://snapshots.lumlabs.io/snapshot-369450000-XYZ.tar.zst -O /home/solana/solana/ledger/snapshot.tar.zst\`

6. Consider rate limiting + bandwidth caps щоб не overwhelm your server.

Most validators do це as community contribution. Some run dedicated snapshot servers separately from validators (just download snapshots + serve).`,explanation:"Module 10.5."}]};return(o,s)=>{const n=t("Quiz");return e(),l("div",null,[s[0]||(s[0]=a(`<h1 id="_5-snapshot-mirror-service" tabindex="-1">5. Snapshot mirror service <a class="header-anchor" href="#_5-snapshot-mirror-service" aria-label="Permalink to &quot;5. Snapshot mirror service&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Solana validators create snapshots locally (Module 5.4). <strong>Snapshot mirror</strong> = make these snapshots HTTP-accessible для other validators catching up. Community contribution, reduces gossip-based fetch load.</p><h2 id="why-mirror-snapshots" tabindex="-1">Why mirror snapshots <a class="header-anchor" href="#why-mirror-snapshots" aria-label="Permalink to &quot;Why mirror snapshots&quot;">​</a></h2><p>Default snapshot fetch:</p><ul><li>New validator connects to gossip-known peers</li><li>Requests snapshot from those peers</li><li>Peers serve via P2P (using their own RPC ports)</li></ul><p>Issues:</p><ul><li>Slow if peers busy</li><li>No централізованих fast download</li><li>Public snapshot URLs (Anza, Helius, third-party) faster</li></ul><p>Snapshot mirrors solve: dedicated HTTP servers з recent snapshots, validators download directly.</p><h2 id="setup-overview" tabindex="-1">Setup overview <a class="header-anchor" href="#setup-overview" aria-label="Permalink to &quot;Setup overview&quot;">​</a></h2><h3 id="_1-validator-generates-snapshots-default" tabindex="-1">1. Validator generates snapshots (default) <a class="header-anchor" href="#_1-validator-generates-snapshots-default" aria-label="Permalink to &quot;1. Validator generates snapshots (default)&quot;">​</a></h3><p>Already happens. Snapshots в <code>/home/solana/solana/ledger/snapshot-*.tar.zst</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/solana/ledger/snapshot-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -5</span></span></code></pre></div><h3 id="_2-http-server-installation" tabindex="-1">2. HTTP server installation <a class="header-anchor" href="#_2-http-server-installation" aria-label="Permalink to &quot;2. HTTP server installation&quot;">​</a></h3><p>Use any web server. Simple nginx config:</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /etc/nginx/sites-enabled/snapshots</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    listen </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">80</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    server_name </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">snapshots.lumlabs.io;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    root </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/var/www/snapshots;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    autoindex </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">on</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    location</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ~*</span><span style="--shiki-light:#032F62;--shiki-dark:#DBEDFF;"> \\.tar\\.zst$ </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Optional rate limit</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        limit_rate </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10m</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        add_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Cache-Control </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;public, max-age=3600&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reload</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span></code></pre></div><h3 id="_3-sync-snapshots-до-web-root" tabindex="-1">3. Sync snapshots до web root <a class="header-anchor" href="#_3-sync-snapshots-до-web-root" aria-label="Permalink to &quot;3. Sync snapshots до web root&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/www/snapshots</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chown</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> www-data:www-data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/www/snapshots</span></span></code></pre></div><p>Periodic sync (cron):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /etc/cron.d/snapshot-sync</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/5 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> root rsync -av --delete </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    /home/solana/solana/ledger/snapshot-*.tar.zst</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    /var/www/snapshots/</span></span></code></pre></div><p>Або symlinks (instant, no copy):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/solana/ledger/snapshot-369450000-XYZ.tar.zst</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">       /var/www/snapshots/snapshot-latest.tar.zst</span></span></code></pre></div><p>(Update symlink when newer snapshot generated.)</p><h3 id="_4-ssl-tls-let-s-encrypt" tabindex="-1">4. SSL / TLS (let&#39;s encrypt) <a class="header-anchor" href="#_4-ssl-tls-let-s-encrypt" aria-label="Permalink to &quot;4. SSL / TLS (let&#39;s encrypt)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> certbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3-certbot-nginx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> certbot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --nginx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> snapshots.lumlabs.io</span></span></code></pre></div><h3 id="_5-publish" tabindex="-1">5. Publish <a class="header-anchor" href="#_5-publish" aria-label="Permalink to &quot;5. Publish&quot;">​</a></h3><p>DNS + Discord announcement:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://snapshots.lumlabs.io/snapshot-latest.tar.zst</span></span>
<span class="line"><span>https://snapshots.lumlabs.io/incremental-snapshot-latest.tar.zst</span></span></code></pre></div><h2 id="consumer-side-catch-up" tabindex="-1">Consumer side (catch-up) <a class="header-anchor" href="#consumer-side-catch-up" aria-label="Permalink to &quot;Consumer side (catch-up)&quot;">​</a></h2><p>Validator wanting to use mirror:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Stop validator</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> solana</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Wipe ledger</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;rm -rf /home/solana/solana/ledger/*&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Download snapshot from mirror</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/solana/ledger</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://snapshots.lumlabs.io/snapshot-latest.tar.zst</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Start validator — auto-detects, uses snapshot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> solana</span></span></code></pre></div><h2 id="existing-public-mirrors" tabindex="-1">Existing public mirrors <a class="header-anchor" href="#existing-public-mirrors" aria-label="Permalink to &quot;Existing public mirrors&quot;">​</a></h2><p>Major Solana operators run public mirrors:</p><ul><li><strong>Helius</strong>: <a href="https://snapshots.helius-rpc.com" target="_blank" rel="noreferrer">https://snapshots.helius-rpc.com</a></li><li><strong>Triton One</strong>: snapshot mirrors через RPC services</li><li><strong>Various validators</strong>: many run mirrors</li></ul><p>Check Solana Discord для current list.</p><h2 id="operational-considerations" tabindex="-1">Operational considerations <a class="header-anchor" href="#operational-considerations" aria-label="Permalink to &quot;Operational considerations&quot;">​</a></h2><h3 id="bandwidth" tabindex="-1">Bandwidth <a class="header-anchor" href="#bandwidth" aria-label="Permalink to &quot;Bandwidth&quot;">​</a></h3><p>Snapshots large (~80GB mainnet full). Serving до ten validators per day = ~800GB outbound. Plan bandwidth quota accordingly.</p><h3 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h3><p>Keep recent snapshots only. Old snapshots invalid (much catch-up still needed).</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Retention policy: keep latest 3 full snapshots</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/www/snapshots</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;snapshot-*.tar.zst&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mtime</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -delete</span></span></code></pre></div><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li>Read-only access (no upload)</li><li>Rate limiting (avoid DDoS amplification)</li><li>HTTPS only (prevent tampering)</li></ul><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><p>Use CDN if global serving. Cloudflare R2 popular для Solana snapshots.</p><h2 id="lumlabs-decision" tabindex="-1">LumLabs decision <a class="header-anchor" href="#lumlabs-decision" aria-label="Permalink to &quot;LumLabs decision&quot;">​</a></h2><p>Running snapshot mirror = community contribution.</p><p>Pros:</p><ul><li>Goodwill у community</li><li>Helps decentralization (more sources)</li><li>May increase brand visibility</li></ul><p>Cons:</p><ul><li>Bandwidth costs</li><li>Operational complexity</li><li>Need monitoring (broken mirrors waste user time)</li></ul><p>For LumLabs scale, optional. Larger operators (Helius, etc.) make sense to provide as service.</p><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,54)),h(n,{data:i}),s[1]||(s[1]=a('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#s"><code>Snapshot mirror</code></a>, <a href="/glossary#p"><code>Public snapshot</code></a></p><hr><p><strong>Попередньо:</strong> <a href="/module-10/4-governance">← 4. Governance</a> | <strong>Наступне:</strong> <a href="/module-10/6-compression-nfts">6. Compression NFTs →</a></p>',4))])}}});export{k as __pageData,c as default};
